public async Task Select_KeyboardNavigation_MultiSelect_Focus()
{
    var comp = Context.Render<MultiSelectTest6>();
    var select = comp.FindComponent<MudSelect<string>>();
    var mudSelectElement = comp.Find(".mud-select");
