@namespace MudBlazor
@typeparam T
@inherits MudBaseInput<T>

<CascadingValue Name="SubscribeToParentForm" Value="false" IsFixed="true">
    <div class="@OuterClassname" id="@ElementId" @onfocusout="@OnFocusOutAsync" @onclick:stopPropagation @onmousedown:stopPropagation>
        <MudInputControl Label="@Label"
                         Variant="@Variant"
                         HelperId="@GetHelperId()"
                         HelperText="@HelperText"
                         HelperTextOnFocus="@HelperTextOnFocus"
                         FullWidth="@FullWidth"
                         Margin="@Margin"
                         Class="@Classname"
                         Style="@Style"
                         Error="@HasErrors"
                         ErrorId="@ErrorIdState.Value"
                         ErrorText="@GetErrorText()"
                         Disabled="@GetDisabledState()"
                         Required="@Required"
                         ForId="@InputElementId"
                         @onmousedown="@HandleMouseDown">
            <InputContent>
                <MudInput @ref="_elementReference"
                          InputType="@(CanRenderValue || (Strict && !IsValueInList) ? InputType.Hidden : InputType.Text)"
                          Class="@InputClassname"
                          Margin="@Margin"
                          Placeholder="@Placeholder"
                          Label="@Label"
                          Variant="@Variant"
                          Typo="@Typo"
                          Value="@(Strict && !IsValueInList ? null : ReadText)"
                          Underline="@Underline"
                          Disabled="@GetDisabledState()"
                          ReadOnly="true"
                          Error="@HasErrors"
                          ErrorId="@ErrorIdState.Value"
                          HelperId="@GetHelperId()"
                          HelperText="@HelperText"
                          AdornmentText="@AdornmentText"
                          AdornmentIcon="@_currentIcon"
                          Adornment="@Adornment"
                          AdornmentColor="@AdornmentColor"
                          IconSize="@IconSize"
                          AdornmentAriaLabel="@AdornmentAriaLabel"
                          OnAdornmentClick="@OnAdornmentClick"
                          Clearable="@(Clearable && !GetReadOnlyState())"
                          ClearIcon="@ClearIcon"
                          OnClearButtonClick="@(async (e) => await SelectClearButtonClickHandlerAsync(e))"
                          @attributes="GetInputUserAttributes()"
                          OnBlur="@OnBlurAsync"
                          ShrinkLabel="@(ShrinkLabel || CanRenderValue)"
                          InputId="@InputElementId"
                          Required="@Required">
                    @if (CanRenderValue)
                    {
                        @GetSelectedValuePresenter()
                    }
                </MudInput>
                @if (FitContent)
                {
                    <MudStack Class="@FillerClassname" Spacing="1" Row>
                        @{
                            var value = string.Empty;

                            if (_longestItem is { Value: not null })
                            {
                                value = ConvertSet(_longestItem.Value) ?? string.Empty;
                            }

                            var useLabel = Label is not null && Placeholder is null && !ShrinkLabel 
                                        && (Adornment != Adornment.Start || (AdornmentIcon is null && AdornmentText is null));

                            var defaultValue = useLabel ? Label : Placeholder;
                            var showDefault = defaultValue?.Length > value.Length;
                            var hasChildContent = _longestItem?.ChildContent is not null;
                            var hasStringValue = ToStringFunc is not null && !string.IsNullOrEmpty(value);

                            var renderText = showDefault || !hasChildContent || MultiSelectionTextFunc is not null || hasStringValue;
                        }

                        @if (renderText)
                        {
                            var text = showDefault ? defaultValue! : value;

                            <MudText Typo="@Typo">
                                @(MultiSelectionTextFunc?.Invoke([text]) ?? text)
                            </MudText>
                        }
                        else
                        {
                            <MudText Typo="@Typo">@_longestItem!.ChildContent</MudText>
                        }

                        @AdornmentText

                        @if (AdornmentText is null)
                        {
                            <MudIcon Icon="@(AdornmentIcon ?? OpenIcon)" Size="IconSize"></MudIcon>
                        }

                        @if (Clearable)
                        {
                            <MudIcon Icon="@ClearIcon" Size="IconSize"></MudIcon>
                        }
                    </MudStack>
                }
                <MudPopover Open="@_openState.Value"
                            MaxHeight="@MaxHeight"
                            Class="@PopoverClass"
                            AnchorOrigin="@AnchorOrigin"
                            TransformOrigin="@TransformOrigin"
                            Fixed="@PopoverFixed"
                            RelativeWidth="@RelativeWidth">
                    <CascadingValue Value="@((IMudSelect)this)" IsFixed="true">
                        <MudList T="string"
                                 @attributes="GetListUserAttributes()"
                                 Class="@ListClass"
                                 Dense="@Dense"
                                 @bind-SelectedValue="_activeItemId">
                            @if (MultiSelection && SelectAll)
                            {
                                <MudListItem Value="@("__SelectAll__")"
                                             Icon="@SelectAllCheckBoxIcon"
                                             Text="@SelectAllText"
                                             OnClick="SelectAllClickAsync"
                                             OnClickPreventDefault="true"
                                             Dense="@Dense"
                                             Class="mb-2" />
                                <MudDivider />
                            }
                            @ChildContent
                        </MudList>
                    </CascadingValue>
                </MudPopover>
            </InputContent>
        </MudInputControl>
    </div>
    @*Shadow select items for IsValueInList and CanRenderValue*@
    <CascadingValue Value="@((IMudShadowSelect)this)" IsFixed="true">
        <CascadingValue Name="HideContent" Value="true">
            @ChildContent
        </CascadingValue>
    </CascadingValue>
</CascadingValue>
<!-- 
pointerdown instead of click needed to close the menu before OnLostFocus runs

When Modal is false the overlay does not receive pointer events so we activate
the auto close feature and call CloseMenu in OnClosed. The modeless auto close
feature relies on pointerdown event resulting in the same order of events.
-->
<MudOverlay Visible="_openState.Value"
            @onpointerdown="@(() => CloseMenu(false))"
            data-modeless-ignore-element-id="@ElementId"
            LockScroll="@LockScroll"
            AutoClose="@(!GetModal())"
            Modal="@GetModal()"
            OnClosed="@(() => CloseMenu(false))"/>

