1	// Copyright (c) MudBlazor 2021
2	// MudBlazor licenses this file to you under the MIT license.
3	// See the LICENSE file in the project root for more information.
4	
5	using System.Collections;
6	using System.Collections.Frozen;
7	using System.Diagnostics.CodeAnalysis;
8	using Microsoft.AspNetCore.Components;
9	using MudBlazor.State.Comparer;
10	using MudBlazor.State.Invocation;
11	
12	namespace MudBlazor.State;
13	
14	/// <summary>
15	/// Represents a collection of multiple <see cref="ParameterScopeContainer"/> instances combined into a union.
16	/// </summary>
17	/// <remarks>
18	/// This class allows combining multiple <see cref="ParameterScopeContainer"/> instances into a single union, enabling the management of parameters across different scope containers.
19	/// </remarks>
20	internal class ParameterContainer : IParameterContainer
21	{
22	    private readonly Lazy<bool> _lazyVerify;
23	    private readonly List<IParameterScopeContainer> _parameterScopeContainers = new();
24	
25	    // Flattened dictionary for O(1) parameter lookups (created lazily on first TryGetValue call)
26	    private readonly Lazy<FrozenDictionary<string, IParameterComponentLifeCycle>> _flattenedParameters;
27	
28	    // Cache handler count for fast path optimization
29	    private int _handlerCount = -1;  // -1 means not computed yet
30	
31	    /// <summary>
32	    /// Gets or sets a value indicating whether the container should automatically verify for duplicates.
33	    /// </summary>
34	    public bool AutoVerify { get; init; } = true;
35	
36	    /// <summary>
37	    /// Gets the number of <see cref="ParameterScopeContainer"/> instances in the union.
38	    /// </summary>
39	    public int Count => _parameterScopeContainers.Count;
40	
41	    /// <summary>
42	    /// Adds a <see cref="ParameterScopeContainer"/> instance to the union container.
43	    /// </summary>
44	    /// <param name="parameterScopeContainer">The <see cref="ParameterScopeContainer"/> instance to add to the union.</param>
45	    public void Add(IParameterScopeContainer parameterScopeContainer) => _parameterScopeContainers.Add(parameterScopeContainer);
46	
47	    /// <summary>
48	    /// Initializes a new instance of the <see cref="ParameterContainer"/> class.
49	    /// </summary>
50	    public ParameterContainer()
51	    {
52	        _lazyVerify = new Lazy<bool>(VerifyInternal);
53	        _flattenedParameters = new Lazy<FrozenDictionary<string, IParameterComponentLifeCycle>>(CreateFlattenedDictionary);
54	    }
55	
56	    /// <summary>
57	    /// Executes <see cref="ParameterScopeContainer.OnInitialized"/> for all registered <see cref="ParameterScopeContainer"/>.
58	    /// </summary>
59	    public void OnInitialized()
60	    {
61	        VerifyOnAuto();
62	
63	        foreach (var parameterSet in _parameterScopeContainers)
64	        {
65	            parameterSet.OnInitialized();
66	        }
67	    }
68	
69	    /// <summary>
70	    /// Executes <see cref="ParameterScopeContainer.OnParametersSet"/> for all registered <see cref="ParameterScopeContainer"/>.
71	    /// </summary>
72	    public void OnParametersSet()
73	    {
74	        VerifyOnAuto();
75	
76	        foreach (var parameterSet in _parameterScopeContainers)
77	        {
78	            parameterSet.OnParametersSet();
79	        }
80	    }
81	
82	    /// <summary>
83	    /// Determines which <see cref="ParameterState{T}"/> have been changed and calls their respective change handler.
84	    /// </summary>
85	    /// <param name="baseSetParametersAsync">A func to call the base class' <see cref="ComponentBase.SetParametersAsync"/>.</param>
86	    /// <param name="parameters">The ParameterView coming from Blazor's  <see cref="ComponentBase.SetParametersAsync"/>.</param>
87	    public Task SetParametersAsync(Func<ParameterView, Task> baseSetParametersAsync, ParameterView parameters)
88	    {
89	        if (Count == 0)
90	        {
91	            return baseSetParametersAsync(parameters);
92	        }
93	
94	        VerifyOnAuto();
95	
96	        // Fast path: if no parameters have change handlers, skip handler detection entirely
97	        if (GetHandlerCount() == 0)
98	        {
99	            return baseSetParametersAsync(parameters);
100	
101	        }
102	
103	        // IMPORTANT: Do not inline the async implementation here.
104	        // Avoid async state machine allocation on the common path by returning the Task directly.
105	        // The async state machine is only used when parameter change handlers must be invoked.
106	        return SetParametersWithHandlersAsync(baseSetParametersAsync, parameters);
107	    }
108	
109	    private async Task SetParametersWithHandlersAsync(Func<ParameterView, Task> baseSetParametersAsync, ParameterView parameters)
110	    {
111	        var handlerCollection = CollectChangedHandlers(parameters);
112	
113	        await baseSetParametersAsync(parameters).ConfigureAwait(false);
114	        await ParameterChangeHandlerUtility.InvokeHandlersAsync(handlerCollection).ConfigureAwait(false);
115	    }
116	
117	    private ParameterChangeHandlerUtility.HandlerCollection? CollectChangedHandlers(ParameterView parameters)
118	    {
119	        List<IParameterStateInvocationSnapshot>? parametersHandlerShouldFire = null;
